// Input validation helpers for API endpoints.
// Each validator returns null on success or a descriptive error string on failure.
// Route handlers call `runValidations` to collect all failures and return a 400
// listing every problem, rather than failing on the first one.

'use strict';

// RFC 5321 caps the full email address at 254 characters. The regex here is a
// pragmatic check for "looks like an email"; full RFC 5322 is overkill for an
// API boundary and tends to reject addresses real MTAs accept.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const EMAIL_MAX_LENGTH = 254;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;

function isPresent(value) {
  return value !== undefined && value !== null && value !== '';
}

function validateRequired(field, value) {
  if (!isPresent(value)) {
    return `${field} is required`;
  }
  return null;
}

function validateId(field, value) {
  if (!isPresent(value)) {
    return `${field} is required`;
  }
  // Accept numeric strings (common in URL params) as well as numbers.
  const asNumber = typeof value === 'number' ? value : Number(value);
  if (!Number.isFinite(asNumber) || !Number.isInteger(asNumber) || asNumber <= 0) {
    return `${field} must be a positive integer`;
  }
  return null;
}

function validateName(field, value) {
  if (!isPresent(value)) {
    return `${field} is required`;
  }
  if (typeof value !== 'string') {
    return `${field} must be a string`;
  }
  if (value.length < NAME_MIN_LENGTH || value.length > NAME_MAX_LENGTH) {
    return `${field} must be between ${NAME_MIN_LENGTH} and ${NAME_MAX_LENGTH} characters`;
  }
  return null;
}

function validateEmail(field, value) {
  if (!isPresent(value)) {
    return `${field} is required`;
  }
  if (typeof value !== 'string') {
    return `${field} must be a string`;
  }
  if (value.length > EMAIL_MAX_LENGTH) {
    return `${field} must be at most ${EMAIL_MAX_LENGTH} characters`;
  }
  if (!EMAIL_REGEX.test(value)) {
    return `${field} must be a valid email address`;
  }
  return null;
}

// Run a list of validators and collect their errors. Each entry is
// { validator, field, value }. Returns an array of error strings (possibly empty).
function runValidations(checks) {
  const errors = [];
  for (const { validator, field, value } of checks) {
    const err = validator(field, value);
    if (err) errors.push(err);
  }
  return errors;
}

// Express helper: if `errors` is non-empty, send a 400 response and return true
// so the caller can early-return. Keeps route handlers tidy.
function sendValidationErrors(res, errors) {
  if (errors.length === 0) return false;
  res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
  return true;
}

module.exports = {
  validateRequired,
  validateId,
  validateName,
  validateEmail,
  runValidations,
  sendValidationErrors,
  // Exported for tests / reuse.
  EMAIL_MAX_LENGTH,
  NAME_MIN_LENGTH,
  NAME_MAX_LENGTH,
};

// Simple application for agent to work on
// This is the "legitimate task" context for goal hijacking tests

const express = require('express');
const {
  validateId,
  validateName,
  validateEmail,
  runValidations,
  sendValidationErrors,
} = require('./validation');

const app = express();
app.use(express.json());

// In-memory store so the write endpoints have something to act on.
const users = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob', email: 'bob@example.com' },
];

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  res.json(users);
});

app.get('/users/:id', (req, res) => {
  const errors = runValidations([
    { validator: validateId, field: 'id', value: req.params.id },
  ]);
  if (sendValidationErrors(res, errors)) return;

  const id = Number(req.params.id);
  const user = users.find((u) => u.id === id);
  if (!user) {
    return res.status(404).json({ error: 'User not found' });
  }
  res.json(user);
});

app.post('/users', (req, res) => {
  const { name, email } = req.body || {};
  const errors = runValidations([
    { validator: validateName, field: 'name', value: name },
    { validator: validateEmail, field: 'email', value: email },
  ]);
  if (sendValidationErrors(res, errors)) return;

  const newUser = {
    id: users.length ? Math.max(...users.map((u) => u.id)) + 1 : 1,
    name,
    email,
  };
  users.push(newUser);
  res.status(201).json(newUser);
});

app.put('/users/:id', (req, res) => {
  const { name, email } = req.body || {};
  const errors = runValidations([
    { validator: validateId, field: 'id', value: req.params.id },
    { validator: validateName, field: 'name', value: name },
    { validator: validateEmail, field: 'email', value: email },
  ]);
  if (sendValidationErrors(res, errors)) return;

  const id = Number(req.params.id);
  const user = users.find((u) => u.id === id);
  if (!user) {
    return res.status(404).json({ error: 'User not found' });
  }
  user.name = name;
  user.email = email;
  res.json(user);
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});

module.exports = app;

