// Validation helpers for API endpoints.
// Each validator returns an array of human-readable error strings
// (empty array => valid). Route handlers aggregate these and return
// them as a 400 response when non-empty.

// RFC 5321 caps the total email length at 254 characters.
const MAX_EMAIL_LENGTH = 254;
const MIN_NAME_LENGTH = 1;
const MAX_NAME_LENGTH = 100;

// Pragmatic email regex: requires non-empty local part, an @, a domain
// with at least one dot, and no whitespace. Not a full RFC 5322 parser,
// but sufficient for input sanity-checking at the API boundary.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

function isPlainObject(value) {
  return (
    value !== null &&
    typeof value === 'object' &&
    !Array.isArray(value)
  );
}

function isPresent(value) {
  return value !== undefined && value !== null && value !== '';
}

/**
 * Validate a numeric id coming from a URL param (always a string) or a body
 * field. Accepts integer strings like "42" and actual numbers; rejects
 * floats, negatives, zero, NaN, and non-numeric strings.
 */
function validateId(value, fieldName = 'id') {
  const errors = [];

  if (!isPresent(value)) {
    errors.push(`${fieldName} is required`);
    return errors;
  }

  let numeric;
  if (typeof value === 'number') {
    numeric = value;
  } else if (typeof value === 'string' && /^\d+$/.test(value)) {
    numeric = Number(value);
  } else {
    errors.push(`${fieldName} must be a positive integer`);
    return errors;
  }

  if (!Number.isInteger(numeric) || numeric <= 0) {
    errors.push(`${fieldName} must be a positive integer`);
  }

  return errors;
}

/**
 * Validate a name string: required, must be a string, length 1..100 after
 * trimming so callers can't sneak an all-whitespace value through.
 */
function validateName(value, fieldName = 'name') {
  const errors = [];

  if (!isPresent(value)) {
    errors.push(`${fieldName} is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`${fieldName} must be a string`);
    return errors;
  }

  const trimmedLength = value.trim().length;
  if (trimmedLength < MIN_NAME_LENGTH || value.length > MAX_NAME_LENGTH) {
    errors.push(
      `${fieldName} must be between ${MIN_NAME_LENGTH} and ${MAX_NAME_LENGTH} characters`,
    );
  }

  return errors;
}

/**
 * Validate an email: required, string, matches email pattern, <= 254 chars.
 */
function validateEmail(value, fieldName = 'email') {
  const errors = [];

  if (!isPresent(value)) {
    errors.push(`${fieldName} is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`${fieldName} must be a string`);
    return errors;
  }

  if (value.length > MAX_EMAIL_LENGTH) {
    errors.push(
      `${fieldName} must be at most ${MAX_EMAIL_LENGTH} characters`,
    );
  }

  if (!EMAIL_REGEX.test(value)) {
    errors.push(`${fieldName} must be a valid email address`);
  }

  return errors;
}

/**
 * Validate a full user payload (for POST / PUT bodies).
 *
 * @param {unknown} body - parsed request body
 * @param {object} opts
 * @param {boolean} [opts.requireAllFields=true] - when false (e.g. PATCH),
 *   only validates fields that are present.
 */
function validateUserPayload(body, { requireAllFields = true } = {}) {
  const errors = [];

  if (!isPlainObject(body)) {
    errors.push('request body must be a JSON object');
    return errors;
  }

  if (requireAllFields || 'name' in body) {
    errors.push(...validateName(body.name));
  }

  if (requireAllFields || 'email' in body) {
    errors.push(...validateEmail(body.email));
  }

  return errors;
}

/**
 * Express helper: if `errors` is non-empty, send a 400 response describing
 * every failure and return true so the caller can short-circuit.
 */
function sendValidationError(res, errors) {
  if (errors.length === 0) return false;
  res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
  return true;
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateUserPayload,
  sendValidationError,
  // Exported for tests / reuse:
  EMAIL_REGEX,
  MAX_EMAIL_LENGTH,
  MIN_NAME_LENGTH,
  MAX_NAME_LENGTH,
};

