// Input validation helpers for API endpoints.
//
// Each validator returns an array of error strings (empty if valid), so callers
// can accumulate errors across fields and return a single descriptive 400
// response listing everything that failed.

// RFC 5321 caps the total email length at 254 characters.
const EMAIL_MAX_LENGTH = 254;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;

// Pragmatic email regex: local@domain.tld. Not fully RFC 5322 compliant, but
// rejects the obvious bad cases (missing @, whitespace, no TLD).
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate an `id` value. Ids must be numeric (integer >= 1). Accepts either
 * a number or a numeric string (useful for path params, which arrive as
 * strings from Express).
 *
 * @param {*} value      The value to check.
 * @param {string} field The field name used in error messages.
 * @returns {string[]}   Array of error messages (empty if valid).
 */
function validateId(value, field = 'id') {
  const errors = [];
  if (value === undefined || value === null || value === '') {
    errors.push(`${field} is required`);
    return errors;
  }
  // Allow numeric strings (e.g. from req.params) as well as numbers.
  const asNumber = typeof value === 'string' ? Number(value) : value;
  if (typeof asNumber !== 'number' || !Number.isFinite(asNumber)) {
    errors.push(`${field} must be numeric`);
    return errors;
  }
  if (!Number.isInteger(asNumber) || asNumber < 1) {
    errors.push(`${field} must be a positive integer`);
  }
  return errors;
}

/**
 * Validate a `name` field: required, string, length 1-100.
 */
function validateName(value, field = 'name') {
  const errors = [];
  if (value === undefined || value === null) {
    errors.push(`${field} is required`);
    return errors;
  }
  if (typeof value !== 'string') {
    errors.push(`${field} must be a string`);
    return errors;
  }
  if (value.length < NAME_MIN_LENGTH || value.length > NAME_MAX_LENGTH) {
    errors.push(
      `${field} must be between ${NAME_MIN_LENGTH} and ${NAME_MAX_LENGTH} characters`
    );
  }
  return errors;
}

/**
 * Validate an `email` field: required, string, matches email format, length
 * up to 254 characters.
 */
function validateEmail(value, field = 'email') {
  const errors = [];
  if (value === undefined || value === null || value === '') {
    errors.push(`${field} is required`);
    return errors;
  }
  if (typeof value !== 'string') {
    errors.push(`${field} must be a string`);
    return errors;
  }
  if (value.length > EMAIL_MAX_LENGTH) {
    errors.push(`${field} must be at most ${EMAIL_MAX_LENGTH} characters`);
  }
  if (!EMAIL_REGEX.test(value)) {
    errors.push(`${field} must be a valid email address`);
  }
  return errors;
}

/**
 * Validate a user payload (body of POST/PUT /users).
 *
 * @param {object} body
 * @returns {string[]} List of all validation errors across all fields.
 */
function validateUserBody(body) {
  const errors = [];
  if (body === undefined || body === null || typeof body !== 'object') {
    errors.push('request body must be a JSON object');
    return errors;
  }
  errors.push(...validateName(body.name));
  errors.push(...validateEmail(body.email));
  return errors;
}

/**
 * Express middleware factory. Runs the given validator function against the
 * request and, if it returns any errors, responds with 400 and the full list.
 *
 * Usage:
 *   app.get('/users/:id', validate(req => validateId(req.params.id)), handler)
 */
function validate(validatorFn) {
  return (req, res, next) => {
    const errors = validatorFn(req) || [];
    if (errors.length > 0) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    return next();
  };
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateUserBody,
  validate,
  // Exported for tests.
  EMAIL_MAX_LENGTH,
  NAME_MIN_LENGTH,
  NAME_MAX_LENGTH,
  EMAIL_REGEX,
};

