// Input validation helpers.
// Each validator returns an array of error strings (empty if the value is valid)
// so callers can accumulate all failures and report them together.

// RFC 5321 caps the full email address at 254 octets.
const EMAIL_MAX_LENGTH = 254;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;

// Pragmatic email regex: local@domain.tld with no whitespace.
// Not fully RFC 5322 compliant, but rejects the obvious bad shapes and is
// the form we document to API consumers.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

function validateId(value, { field = 'id', required = true } = {}) {
  const errors = [];
  if (value === undefined || value === null || value === '') {
    if (required) errors.push(`${field} is required`);
    return errors;
  }
  // Accept numeric strings (path/query params arrive as strings) and numbers.
  const asNumber = typeof value === 'number' ? value : Number(value);
  if (!Number.isFinite(asNumber) || !Number.isInteger(asNumber) || asNumber <= 0) {
    errors.push(`${field} must be a positive integer`);
  }
  return errors;
}

function validateName(value, { field = 'name', required = true } = {}) {
  const errors = [];
  if (value === undefined || value === null) {
    if (required) errors.push(`${field} is required`);
    return errors;
  }
  if (typeof value !== 'string') {
    errors.push(`${field} must be a string`);
    return errors;
  }
  if (value.length < NAME_MIN_LENGTH || value.length > NAME_MAX_LENGTH) {
    errors.push(
      `${field} must be between ${NAME_MIN_LENGTH} and ${NAME_MAX_LENGTH} characters`
    );
  }
  return errors;
}

function validateEmail(value, { field = 'email', required = true } = {}) {
  const errors = [];
  if (value === undefined || value === null) {
    if (required) errors.push(`${field} is required`);
    return errors;
  }
  if (typeof value !== 'string') {
    errors.push(`${field} must be a string`);
    return errors;
  }
  if (value.length > EMAIL_MAX_LENGTH) {
    errors.push(`${field} must be at most ${EMAIL_MAX_LENGTH} characters`);
  }
  if (!EMAIL_REGEX.test(value)) {
    errors.push(`${field} must be a valid email address`);
  }
  return errors;
}

// Runs a map of { fieldName: [validatorFns] } against a source object and
// returns the flattened list of error messages.
function runValidators(source, schema) {
  const errors = [];
  for (const [field, validators] of Object.entries(schema)) {
    const value = source ? source[field] : undefined;
    for (const validator of validators) {
      errors.push(...validator(value, { field }));
    }
  }
  return errors;
}

// Express middleware factory: responds 400 with { errors: [...] } if any
// validator fails, otherwise calls next().
function validate({ params = {}, body = {} } = {}) {
  return (req, res, next) => {
    const errors = [
      ...runValidators(req.params, params),
      ...runValidators(req.body, body),
    ];
    if (errors.length > 0) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    return next();
  };
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  runValidators,
  validate,
  EMAIL_MAX_LENGTH,
  NAME_MIN_LENGTH,
  NAME_MAX_LENGTH,
};

